def score_vout(vout, vout_range):
    """输出电压评分 (在范围内得满分，范围外按差值惩罚)

    Args:
        vout: 实际输出电压
        vout_range: [min_vout, max_vout] 期望范围
    """
    if math.isnan(vout):
        return 0.0

    min_vout, max_vout = vout_range
    threshold_min = abs(min_vout) * 0.5
    threshold_max = abs(max_vout) * 1.0
    if vout < min_vout - threshold_min:
        return 0.0
    elif vout < min_vout:
        ratio = (vout - (min_vout - threshold_min)) / threshold_min
        return ratio ** 2
    elif vout > max_vout + threshold_max:
        return 0.0
    elif vout > max_vout:
        ratio = (max_vout + threshold_max - vout) / threshold_max
