def compute_trend_score(rewards):
    """计算序列的增长趋势得分(0-1)"""
    # 检查是否所有奖励值都相同
    if len(set(rewards)) == 1:
        return 0.5  # 所有值相同，无趋势

    try:
        time_points = np.arange(len(rewards))
        rho, _ = spearmanr(time_points, rewards)

        # 处理NaN情况
        if np.isnan(rho):
            return 0.5

        return (rho + 1) / 2
    except:
        return 0.5  # 异常情况返回中性值

