def acs_simplify_context(context: str) -> str:
    # print(f"debug: context {context}")
    extracted_parts = []

    # 首先从prompt中提取"## 待优化参数的初始值"部分
    initial_values_pattern = r'## 待优化参数的初始值\s*\n当前电路网表中，待优化参数的初始值设定如下：\s*\n(.*?)(?=\n##|\Z)'
    initial_match = re.search(initial_values_pattern, context, re.DOTALL)
    if initial_match:
        initial_values_text = initial_match.group(1).strip()
        if initial_values_text:
            extracted_parts.append(f'## 初始工具调用参数\n\n{initial_values_text}')

    extracted_parts.append("\n## 历史轮次的工具调用\n")

    # 然后提取所有成对的 tool_call 和 tool_response
    tool_call_pattern = r'<tool_call>.*?</tool_call>'
    tool_response_pattern = r'<tool_response>.*?</tool_response>'

    # 使用 finditer 按顺序找到所有的 tool_call 和 tool_response，保持原始顺序
    matches = []
    for match in re.finditer(tool_call_pattern, context, re.DOTALL):
        matches.append(('tool_call', match.start(), match.group(0)))
    for match in re.finditer(tool_response_pattern, context, re.DOTALL):
        matches.append(('tool_response', match.start(), match.group(0)))

    # 按照在原文本中的位置排序
    matches.sort(key=lambda x: x[1])

    # 构建输出内容，只保留成对的 tool_call 和 tool_response
    tool_call_count = 0
    i = 0
    while i < len(matches):
        tag, pos, content = matches[i]
        if tag == 'tool_call':
            # 检查下一个匹配项是否是 tool_response
            if i + 1 < len(matches) and matches[i + 1][0] == 'tool_response':
                # 找到成对的内容，保留并计数
                tool_call_content = content
                tool_response_content = matches[i + 1][2]

                # 从第1轮开始计数（因为初始参数已经从prompt中提取）
                tool_call_count += 1
                extracted_parts.append(f'第{tool_call_count}轮工具调用\n{tool_call_content}\n{tool_response_content}\n')

                i += 2  # 跳过已处理的 tool_response
            else:
                # 没有对应的 tool_response，跳过这个 tool_call
                i += 1
        else:
            # 单独的 tool_response，跳过
            i += 1

    extracted_content = '\n'.join(extracted_parts)
    # print(f"debug: extracted_content {extracted_content}")
    return extracted_content

def acs_simplify_response(response: str) -> str:
    pattern = r'user\n<tool_response>[\s\S]*$'
    # 删除匹配的内容
    result = re.sub(pattern, '', response)
    return result
